1	/*
2	 * DS4 quantization facade.
3	 *
4	 * These are the small GGUF quantization pieces needed by our DeepSeek V4
5	 * Flash recipes: float conversion, q8_0, q2_K, q4_K, and iq2_xxs.  The code is
6	 * local C and deliberately narrow; other GGUF type IDs are named for metadata
7	 * compatibility, but cannot be emitted by this tool.
8	 *
9	 * The quantized block layouts and search procedures are derived from the
10	 * MIT-licensed GGML/llama.cpp quantizers.  Keep changes conservative: byte
11	 * layout compatibility is more important here than generality.
12	 */
13	
14	#include "quants.h"
15	
16	#include <assert.h>
17	#include <float.h>
18	#include <math.h>
19	#include <pthread.h>
20	#include <stdint.h>
21	#include <stdlib.h>
22	#include <string.h>
23	
24	static pthread_mutex_t ds4q_init_mutex = PTHREAD_MUTEX_INITIALIZER;
25	
26	typedef struct {
27	    const char *name;
28	    int64_t block_size;
29	    size_t type_size;
30	    bool can_quantize;
31	    bool requires_imatrix;
32	} ds4q_traits;
33	
34	#define QK_K 256
35	#define DS4Q_GROUP_MAX_EPS 1e-15f
36	#define DS4Q_MIN(a, b) ((a) < (b) ? (a) : (b))
37	#define DS4Q_MAX(a, b) ((a) > (b) ? (a) : (b))
38	
39	static const ds4q_traits ds4q_type_traits[DS4Q_TYPE_COUNT] = {
40	    [DS4Q_TYPE_F32]     = { "f32",      1,   4, false, false },
41	    [DS4Q_TYPE_F16]     = { "f16",      1,   2, false, false },
42	    [DS4Q_TYPE_Q4_0]    = { "q4_0",    32,  18, false, false },
43	    [DS4Q_TYPE_Q4_1]    = { "q4_1",    32,  20, false, false },
44	    [DS4Q_TYPE_Q5_0]    = { "q5_0",    32,  22, false, false },
45	    [DS4Q_TYPE_Q5_1]    = { "q5_1",    32,  24, false, false },
46	    [DS4Q_TYPE_Q8_0]    = { "q8_0",    32,  34, true,  false },
47	    [DS4Q_TYPE_Q8_1]    = { "q8_1",    32,  36, false, false },
48	    [DS4Q_TYPE_Q2_K]    = { "q2_K",  QK_K,  84, true,  false },
49	    [DS4Q_TYPE_Q3_K]    = { "q3_K",  QK_K, 110, false, false },
50	    [DS4Q_TYPE_Q4_K]    = { "q4_K",  QK_K, 144, true,  false },
51	    [DS4Q_TYPE_Q5_K]    = { "q5_K",  QK_K, 176, false, false },
52	    [DS4Q_TYPE_Q6_K]    = { "q6_K",  QK_K, 210, false, false },
53	    [DS4Q_TYPE_Q8_K]    = { "q8_K",  QK_K, 292, false, false },
54	    [DS4Q_TYPE_IQ2_XXS] = { "iq2_xxs", QK_K,  66, true,  true  },
55	    [DS4Q_TYPE_IQ2_XS]  = { "iq2_xs",  QK_K,  74, false, true  },
56	    [DS4Q_TYPE_IQ3_XXS] = { "iq3_xxs", QK_K,  98, false, false },
57	    [DS4Q_TYPE_IQ1_S]   = { "iq1_s",   QK_K,  50, false, true  },
58	    [DS4Q_TYPE_IQ4_NL]  = { "iq4_nl",     32,  18, false, false },
59	    [DS4Q_TYPE_IQ3_S]   = { "iq3_s",   QK_K, 110, false, false },
60	    [DS4Q_TYPE_IQ2_S]   = { "iq2_s",   QK_K,  82, false, false },
61	    [DS4Q_TYPE_IQ4_XS]  = { "iq4_xs",  QK_K, 136, false, false },
62	    [DS4Q_TYPE_I8]      = { "i8",          1,   1, false, false },
63	    [DS4Q_TYPE_I16]     = { "i16",         1,   2, false, false },
64	    [DS4Q_TYPE_I32]     = { "i32",         1,   4, false, false },
65	    [DS4Q_TYPE_I64]     = { "i64",         1,   8, false, false },
66	    [DS4Q_TYPE_F64]     = { "f64",         1,   8, false, false },
67	    [DS4Q_TYPE_IQ1_M]   = { "iq1_m",   QK_K,  56, false, false },
68	    [DS4Q_TYPE_BF16]    = { "bf16",        1,   2, false, false },
69	    [DS4Q_TYPE_TQ1_0]   = { "tq1_0",   QK_K,  54, false, false },
70	    [DS4Q_TYPE_TQ2_0]   = { "tq2_0",   QK_K,  66, false, false },
71	    [DS4Q_TYPE_MXFP4]   = { "mxfp4",      32,  17, false, false },
72	    [DS4Q_TYPE_NVFP4]   = { "nvfp4",      64,  36, false, false },
73	    [DS4Q_TYPE_Q1_0]    = { "q1_0",      128,  18, false, false },
74	};
75	
76	static float ds4q_f32_from_bits(uint32_t bits) {
77	    union {
78	        uint32_t u;
79	        float f;
80	    } v = { .u = bits };
81	    return v.f;
82	}
83	
84	static uint32_t ds4q_f32_to_bits(float f) {
85	    union {
86	        float f;
87	        uint32_t u;
88	    } v = { .f = f };
89	    return v.u;
90	}
91	
92	static uint16_t ds4q_f32_to_f16(float f) {
93	    const float scale_to_inf = 0x1.0p+112f;
94	    const float scale_to_zero = 0x1.0p-110f;
95	    float base = (fabsf(f) * scale_to_inf) * scale_to_zero;
96	
97	    const uint32_t w = ds4q_f32_to_bits(f);
98	    const uint32_t shl1_w = w + w;
99	    const uint32_t sign = w & UINT32_C(0x80000000);
100	    uint32_t bias = shl1_w & UINT32_C(0xFF000000);
101	    if (bias < UINT32_C(0x71000000)) bias = UINT32_C(0x71000000);
102	
103	    base = ds4q_f32_from_bits((bias >> 1) + UINT32_C(0x07800000)) + base;
104	    const uint32_t out = ds4q_f32_to_bits(base);
105	    const uint32_t exp_bits = (out >> 13) & UINT32_C(0x00007C00);
106	    const uint32_t mantissa_bits = out & UINT32_C(0x00000FFF);
107	    const uint32_t nonsign = exp_bits + mantissa_bits;
108	    return (uint16_t)((sign >> 16) | (shl1_w > UINT32_C(0xFF000000) ? UINT16_C(0x7E00) : nonsign));
109	}
110	
111	static int ds4q_nearest_int(float fval) {
112	    assert(fabsf(fval) <= 4194303.f);
113	    float val = fval + 12582912.f;
114	    int i;
115	    memcpy(&i, &val, sizeof(i));
116	    return (i & 0x007fffff) - 0x00400000;
117	}
118	
119	static float ds4q_make_qkx2_quants(int n, int nmax, const float *x, const float *weights,
120	                                   uint8_t *L, float *the_min, uint8_t *Laux,
121	                                   float rmin, float rdelta, int nstep, bool use_mad) {
122	    float min = x[0];
123	    float max = x[0];
124	    float sum_w = weights[0];
125	    float sum_x = sum_w * x[0];
126	    for (int i = 1; i < n; i++) {
127	        if (x[i] < min) min = x[i];
128	        if (x[i] > max) max = x[i];
129	        float w = weights[i];
130	        sum_w += w;
131	        sum_x += w * x[i];
132	    }
133	    if (min > 0) min = 0;
134	    if (max == min) {
135	        memset(L, 0, (size_t)n);
136	        *the_min = -min;
137	        return 0.0f;
138	    }
139	    float iscale = nmax / (max - min);
140	    float scale = 1 / iscale;
141	    float best_error = 0;
142	    for (int i = 0; i < n; i++) {
143	        int l = ds4q_nearest_int(iscale * (x[i] - min));
144	        L[i] = DS4Q_MAX(0, DS4Q_MIN(nmax, l));
145	        float diff = scale * L[i] + min - x[i];
146	        diff = use_mad ? fabsf(diff) : diff * diff;
147	        best_error += weights[i] * diff;
148	    }
149	    if (nstep < 1) {
150	        *the_min = -min;
151	        return scale;
152	    }
153	    for (int is = 0; is <= nstep; is++) {
154	        iscale = (rmin + rdelta * is + nmax) / (max - min);
155	        float sum_l = 0, sum_l2 = 0, sum_xl = 0;
156	        for (int i = 0; i < n; i++) {
157	            int l = ds4q_nearest_int(iscale * (x[i] - min));
158	            l = DS4Q_MAX(0, DS4Q_MIN(nmax, l));
159	            Laux[i] = l;
160	            float w = weights[i];
161	            sum_l += w * l;
162	            sum_l2 += w * l * l;
163	            sum_xl += w * l * x[i];
164	        }
165	        float D = sum_w * sum_l2 - sum_l * sum_l;
166	        if (D > 0) {
167	            float this_scale = (sum_w * sum_xl - sum_x * sum_l) / D;
168	            float this_min = (sum_l2 * sum_x - sum_l * sum_xl) / D;
169	            if (this_min > 0) {
170	                this_min = 0;
171	                this_scale = sum_xl / sum_l2;
172	            }
173	            float cur_error = 0;
174	            for (int i = 0; i < n; i++) {
175	                float diff = this_scale * Laux[i] + this_min - x[i];
176	                diff = use_mad ? fabsf(diff) : diff * diff;
177	                cur_error += weights[i] * diff;
178	            }
179	            if (cur_error < best_error) {
180	                memcpy(L, Laux, (size_t)n);
181	                best_error = cur_error;
182	                scale = this_scale;
183	                min = this_min;
184	            }
185	        }
186	    }
187	    *the_min = -min;
188	    return scale;
189	}
190	
191	static float ds4q_make_qkx3_quants(int n, int nmax, const float *x, const float *weights,
192	                                   uint8_t *L, float *the_min, uint8_t *Laux,
193	                                   float rmin, float rdelta, int nstep, bool use_mad) {
194	    float min = x[0];
195	    float max = x[0];
196	    float sum_w = weights ? weights[0] : x[0] * x[0];
197	    float sum_x = sum_w * x[0];
198	    for (int i = 1; i < n; i++) {
199	        if (x[i] < min) min = x[i];
200	        if (x[i] > max) max = x[i];
201	        float w = weights ? weights[i] : x[i] * x[i];
202	        sum_w += w;
203	        sum_x += w * x[i];
204	    }
205	    if (min > 0) min = 0;
206	    if (max <= min) {
207	        memset(L, 0, (size_t)n);
208	        *the_min = -min;
209	        return 0.0f;
210	    }
211	    float iscale = nmax / (max - min);
212	    float scale = 1 / iscale;
213	    float best_mad = 0;
214	    for (int i = 0; i < n; i++) {
215	        int l = ds4q_nearest_int(iscale * (x[i] - min));
216	        L[i] = DS4Q_MAX(0, DS4Q_MIN(nmax, l));
217	        float diff = scale * L[i] + min - x[i];
218	        diff = use_mad ? fabsf(diff) : diff * diff;
219	        float w = weights ? weights[i] : x[i] * x[i];
220	        best_mad += w * diff;
221	    }
222	    if (nstep < 1) {
223	        *the_min = -min;
224	        return scale;
225	    }
226	    for (int is = 0; is <= nstep; is++) {
227	        iscale = (rmin + rdelta * is + nmax) / (max - min);
228	        float sum_l = 0, sum_l2 = 0, sum_xl = 0;
229	        for (int i = 0; i < n; i++) {
230	            int l = ds4q_nearest_int(iscale * (x[i] - min));
231	            l = DS4Q_MAX(0, DS4Q_MIN(nmax, l));
232	            Laux[i] = l;
233	            float w = weights ? weights[i] : x[i] * x[i];
234	            sum_l += w * l;
235	            sum_l2 += w * l * l;
236	            sum_xl += w * l * x[i];
237	        }
238	        float D = sum_w * sum_l2 - sum_l * sum_l;
239	        if (D > 0) {
240	            float this_scale = (sum_w * sum_xl - sum_x * sum_l) / D;
241	            float this_min = (sum_l2 * sum_x - sum_l * sum_xl) / D;
242	            if (this_min > 0) {
243	                this_min = 0;
244	                this_scale = sum_xl / sum_l2;
245	            }
246	            float mad = 0;
247	            for (int i = 0; i < n; i++) {
248	                float diff = this_scale * Laux[i] + this_min - x[i];
249	                diff = use_mad ? fabsf(diff) : diff * diff;
250	                float w = weights ? weights[i] : x[i] * x[i];
251	                mad += w * diff;
252	            }
253	            if (mad < best_mad) {
254	                memcpy(L, Laux, (size_t)n);
255	                best_mad = mad;
256	                scale = this_scale;
257	                min = this_min;
258	            }
259	        }
260	    }
261	    *the_min = -min;
262	    return scale;
263	}
264	
265	static float ds4q_make_qp_quants(int n, int nmax, const float *x, uint8_t *L, const float *quant_weights) {
266	    float max = 0;
267	    for (int i = 0; i < n; i++) max = DS4Q_MAX(max, x[i]);
268	    if (max < DS4Q_GROUP_MAX_EPS) {
269	        memset(L, 0, (size_t)n);
270	        return 0.0f;
271	    }
272	    float iscale = nmax / max;
273	    for (int i = 0; i < n; i++) L[i] = ds4q_nearest_int(iscale * x[i]);
274	    float scale = 1 / iscale;
275	    float best_mse = 0;
276	    for (int i = 0; i < n; i++) {
277	        float diff = x[i] - scale * L[i];
278	        best_mse += quant_weights[i] * diff * diff;
279	    }
280	    for (int is = -4; is <= 4; is++) {
281	        if (is == 0) continue;
282	        float iscale_is = (0.1f * is + nmax) / max;
283	        float scale_is = 1 / iscale_is;
284	        float mse = 0;
285	        for (int i = 0; i < n; i++) {
286	            int l = ds4q_nearest_int(iscale_is * x[i]);
287	            l = DS4Q_MIN(nmax, l);
288	            float diff = x[i] - scale_is * l;
289	            mse += quant_weights[i] * diff * diff;
290	        }
291	        if (mse < best_mse) {
292	            best_mse = mse;
293	            iscale = iscale_is;
294	        }
295	    }
296	    float sumlx = 0, suml2 = 0;
297	    for (int i = 0; i < n; i++) {
298	        int l = ds4q_nearest_int(iscale * x[i]);
299	        l = DS4Q_MIN(nmax, l);
300	        L[i] = l;
301	        float w = quant_weights[i];
302	        sumlx += w * x[i] * l;
303	        suml2 += w * l * l;
304	    }
305	    for (int itry = 0; itry < 5; itry++) {
306	        int n_changed = 0;
307	        for (int i = 0; i < n; i++) {
308	            float w = quant_weights[i];
309	            float slx = sumlx - w * x[i] * L[i];
310	            float sl2 = suml2 - w * L[i] * L[i];
311	            if (slx > 0 && sl2 > 0) {
312	                int new_l = ds4q_nearest_int(x[i] * sl2 / slx);
313	                new_l = DS4Q_MIN(nmax, new_l);
314	                if (new_l != L[i]) {
315	                    slx += w * x[i] * new_l;
316	                    sl2 += w * new_l * new_l;
317	                    if (slx * slx * suml2 > sumlx * sumlx * sl2) {
318	                        L[i] = new_l;
319	                        sumlx = slx;
320	                        suml2 = sl2;
321	                        n_changed++;
322	                    }
323	                }
324	            }
325	        }
326	        if (!n_changed) break;
327	    }
328	    return suml2 > 0.0f ? sumlx / suml2 : 0.0f;
329	}
330	
331	static void ds4q_get_scale_min_k4(int j, const uint8_t *q, uint8_t *d, uint8_t *m) {
332	    if (j < 4) {
333	        *d = q[j] & 63;
334	        *m = q[j + 4] & 63;
335	    } else {
336	        *d = (q[j + 4] & 0xF) | ((q[j - 4] >> 6) << 4);
337	        *m = (q[j + 4] >> 4) | ((q[j - 0] >> 6) << 4);
338	    }
339	}
340	
341	static size_t ds4q_quantize_q8_0(const float *src, void *dst, int64_t start,
342	                                 int64_t nrows, int64_t ncols) {
343	    const int64_t qk = 32;
344	    const size_t row_size = ds4q_row_size(DS4Q_TYPE_Q8_0, ncols);
345	    const int64_t start_row = start / ncols;
346	    uint8_t *out = (uint8_t *)dst + (size_t)start_row * row_size;
347	    const int64_t nblocks = nrows * (ncols / qk);
348	
349	    for (int64_t b = 0; b < nblocks; b++) {
350	        const float *x = src + start + (size_t)b * qk;
351	        float amax = 0.0f;
352	        for (int j = 0; j < qk; j++) {
353	            const float av = fabsf(x[j]);
354	            if (av > amax) amax = av;
355	        }
356	
357	        const float d = amax / 127.0f;
358	        const float id = d ? 1.0f / d : 0.0f;
359	        const uint16_t hd = ds4q_f32_to_f16(d);
360	        memcpy(out, &hd, sizeof(hd));
361	
362	        int8_t *qs = (int8_t *)(out + sizeof(hd));
363	        for (int j = 0; j < qk; j++) qs[j] = (int8_t)roundf(x[j] * id);
364	        out += sizeof(hd) + qk;
365	    }
366	    return (size_t)nrows * row_size;
367	}
368	
369	static void ds4q_write_q4_k_block_ref(const float *x, uint8_t *y) {
370	    enum { scales_off = 4, qs_off = 16 };
371	    uint8_t L[QK_K];
372	    uint8_t Laux[32];
373	    float weights[32];
374	    float mins[QK_K / 32];
375	    float scales[QK_K / 32];
376	    uint8_t *scales_out = y + scales_off;
377	    uint8_t *qs_out = y + qs_off;
378	
379	    float max_scale = 0;
380	    float max_min = 0;
381	    for (int j = 0; j < QK_K / 32; j++) {
382	        float sum_x2 = 0;
383	        for (int l = 0; l < 32; l++) sum_x2 += x[32 * j + l] * x[32 * j + l];
384	        float av_x = sqrtf(sum_x2 / 32);
385	        for (int l = 0; l < 32; l++) weights[l] = av_x + fabsf(x[32 * j + l]);
386	        scales[j] = ds4q_make_qkx2_quants(32, 15, x + 32 * j, weights, L + 32 * j,
387	                                           &mins[j], Laux, -1.0f, 0.1f, 20, false);
388	        if (scales[j] > max_scale) max_scale = scales[j];
389	        if (mins[j] > max_min) max_min = mins[j];
390	    }
391	
392	    float inv_scale = max_scale > 0 ? 63.0f / max_scale : 0.0f;
393	    float inv_min = max_min > 0 ? 63.0f / max_min : 0.0f;
394	    for (int j = 0; j < QK_K / 32; j++) {
395	        uint8_t ls = ds4q_nearest_int(inv_scale * scales[j]);
396	        uint8_t lm = ds4q_nearest_int(inv_min * mins[j]);
397	        ls = DS4Q_MIN(63, ls);
398	        lm = DS4Q_MIN(63, lm);
399	        if (j < 4) {
400	            scales_out[j] = ls;
401	            scales_out[j + 4] = lm;
402	        } else {
403	            scales_out[j + 4] = (ls & 0xF) | ((lm & 0xF) << 4);
404	            scales_out[j - 4] |= ((ls >> 4) << 6);
405	            scales_out[j - 0] |= ((lm >> 4) << 6);
406	        }
407	    }
408	
409	    uint16_t d = ds4q_f32_to_f16(max_scale / 63.0f);
410	    uint16_t dmin = ds4q_f32_to_f16(max_min / 63.0f);
411	    memcpy(y + 0, &d, sizeof(d));
412	    memcpy(y + 2, &dmin, sizeof(dmin));
413	
414	    uint8_t sc, m;
415	    for (int j = 0; j < QK_K / 32; j++) {
416	        ds4q_get_scale_min_k4(j, scales_out, &sc, &m);
417	        const float dd = ds4q_f16_to_f32(d) * sc;
418	        if (!dd) continue;
419	        const float dm = ds4q_f16_to_f32(dmin) * m;
420	        for (int ii = 0; ii < 32; ii++) {
421	            int l = ds4q_nearest_int((x[32 * j + ii] + dm) / dd);
422	            l = DS4Q_MAX(0, DS4Q_MIN(15, l));
423	            L[32 * j + ii] = l;
424	        }
425	    }
426	
427	    uint8_t *q = qs_out;
428	    for (int j = 0; j < QK_K; j += 64) {
429	        for (int l = 0; l < 32; l++) q[l] = L[j + l] | (L[j + l + 32] << 4);
430	        q += 32;
431	    }
432	}
433	
434	static void ds4q_write_q4_k_block_weighted(const float *x, uint8_t *y, const float *quant_weights) {
435	    enum { scales_off = 4, qs_off = 16 };
436	    uint8_t L[QK_K];
437	    uint8_t Laux[32];
438	    uint8_t Ls[QK_K / 32];
439	    uint8_t Lm[QK_K / 32];
440	    float weights[32];
441	    float sw[QK_K / 32];
442	    float mins[QK_K / 32];
443	    float scales[QK_K / 32];
444	    uint8_t *scales_out = y + scales_off;
445	    uint8_t *qs_out = y + qs_off;
446	
447	    float sum_x2 = 0;
448	    for (int l = 0; l < QK_K; l++) sum_x2 += x[l] * x[l];
449	    float sigma2 = 2 * sum_x2 / QK_K;
450	    float av_x = sqrtf(sigma2);
451	
452	    for (int j = 0; j < QK_K / 32; j++) {
453	        if (quant_weights) {
454	            const float *qw = quant_weights + 32 * j;
455	            for (int l = 0; l < 32; l++) weights[l] = qw[l] * sqrtf(sigma2 + x[32 * j + l] * x[32 * j + l]);
456	        } else {
457	            for (int l = 0; l < 32; l++) weights[l] = av_x + fabsf(x[32 * j + l]);
458	        }
459	        float sumw = 0;
460	        for (int l = 0; l < 32; l++) sumw += weights[l];
461	        sw[j] = sumw;
462	        scales[j] = ds4q_make_qkx3_quants(32, 15, x + 32 * j, weights, L + 32 * j,
463	                                           &mins[j], Laux, -0.9f, 0.05f, 36, false);
464	    }
465	
466	    float d_block = ds4q_make_qp_quants(QK_K / 32, 63, scales, Ls, sw);
467	    float m_block = ds4q_make_qp_quants(QK_K / 32, 63, mins, Lm, sw);
468	    for (int j = 0; j < QK_K / 32; j++) {
469	        uint8_t ls = Ls[j];
470	        uint8_t lm = Lm[j];
471	        if (j < 4) {
472	            scales_out[j] = ls;
473	            scales_out[j + 4] = lm;
474	        } else {
475	            scales_out[j + 4] = (ls & 0xF) | ((lm & 0xF) << 4);
476	            scales_out[j - 4] |= ((ls >> 4) << 6);
477	            scales_out[j - 0] |= ((lm >> 4) << 6);
478	        }
479	    }
480	
481	    uint16_t d = ds4q_f32_to_f16(d_block);
482	    uint16_t dmin = ds4q_f32_to_f16(m_block);
483	    memcpy(y + 0, &d, sizeof(d));
484	    memcpy(y + 2, &dmin, sizeof(dmin));
485	
486	    uint8_t sc, m;
487	    for (int j = 0; j < QK_K / 32; j++) {
488	        ds4q_get_scale_min_k4(j, scales_out, &sc, &m);
489	        const float dd = ds4q_f16_to_f32(d) * sc;
490	        if (!dd) continue;
491	        const float dm = ds4q_f16_to_f32(dmin) * m;
492	        for (int ii = 0; ii < 32; ii++) {
493	            int l = ds4q_nearest_int((x[32 * j + ii] + dm) / dd);
494	            l = DS4Q_MAX(0, DS4Q_MIN(15, l));
495	            L[32 * j + ii] = l;
496	        }
497	    }
498	
499	    uint8_t *q = qs_out;
500	    for (int j = 0; j < QK_K; j += 64) {
501	        for (int l = 0; l < 32; l++) q[l] = L[j + l] | (L[j + l + 32] << 4);
502	        q += 32;
503	    }
504	}
505	
506	static size_t ds4q_quantize_q4_k(const float *src, void *dst, int64_t start,
507	                                 int64_t nrows, int64_t ncols, const float *quant_weights) {
508	    const size_t row_size = ds4q_row_size(DS4Q_TYPE_Q4_K, ncols);
509	    const int64_t start_row = start / ncols;
510	    uint8_t *out = (uint8_t *)dst + (size_t)start_row * row_size;
511	    const int64_t blocks_per_row = ncols / QK_K;
512	
513	    for (int64_t row = 0; row < nrows; row++) {
514	        const float *xrow = src + start + (size_t)row * (size_t)ncols;
515	        for (int64_t b = 0; b < blocks_per_row; b++) {
516	            uint8_t *block = out + (size_t)row * row_size + (size_t)b * ds4q_type_traits[DS4Q_TYPE_Q4_K].type_size;
517	            const float *x = xrow + (size_t)b * QK_K;
518	            if (quant_weights) {
519	                ds4q_write_q4_k_block_weighted(x, block, quant_weights + (size_t)b * QK_K);
520	            } else {
521	                ds4q_write_q4_k_block_ref(x, block);
522	            }
523	        }
524	    }
525	    return (size_t)nrows * row_size;
526	}
