528	static void ds4q_write_q2_k_block_ref(const float *x, uint8_t *y) {
529	    enum { scales_off = 0, qs_off = 16, d_off = 80, dmin_off = 82 };
530	    const float q4scale = 15.0f;
531	    uint8_t L[QK_K];
532	    uint8_t Laux[16];
533	    float weights[16];
534	    float mins[QK_K / 16];
535	    float scales[QK_K / 16];
536	    uint8_t *scales_out = y + scales_off;
537	    uint8_t *qs_out = y + qs_off;
538	
539	    float max_scale = 0;
540	    float max_min = 0;
541	    for (int j = 0; j < QK_K / 16; j++) {
542	        for (int l = 0; l < 16; l++) weights[l] = fabsf(x[16 * j + l]);
543	        scales[j] = ds4q_make_qkx2_quants(16, 3, x + 16 * j, weights, L + 16 * j,
544	                                           &mins[j], Laux, -0.5f, 0.1f, 15, true);
545	        if (scales[j] > max_scale) max_scale = scales[j];
546	        if (mins[j] > max_min) max_min = mins[j];
547	    }
548	
549	    uint16_t hd, hmin;
550	    if (max_scale > 0) {
551	        float iscale = q4scale / max_scale;
552	        for (int j = 0; j < QK_K / 16; j++) scales_out[j] = ds4q_nearest_int(iscale * scales[j]);
553	        hd = ds4q_f32_to_f16(max_scale / q4scale);
554	    } else {
555	        memset(scales_out, 0, QK_K / 16);
556	        hd = ds4q_f32_to_f16(0.0f);
557	    }
558	    if (max_min > 0) {
559	        float iscale = q4scale / max_min;
560	        for (int j = 0; j < QK_K / 16; j++) scales_out[j] |= ds4q_nearest_int(iscale * mins[j]) << 4;
561	        hmin = ds4q_f32_to_f16(max_min / q4scale);
562	    } else {
563	        hmin = ds4q_f32_to_f16(0.0f);
564	    }
565	    memcpy(y + d_off, &hd, sizeof(hd));
566	    memcpy(y + dmin_off, &hmin, sizeof(hmin));
567	
568	    for (int j = 0; j < QK_K / 16; j++) {
569	        const float d = ds4q_f16_to_f32(hd) * (scales_out[j] & 0xF);
570	        if (!d) continue;
571	        const float dm = ds4q_f16_to_f32(hmin) * (scales_out[j] >> 4);
572	        for (int ii = 0; ii < 16; ii++) {
573	            int l = ds4q_nearest_int((x[16 * j + ii] + dm) / d);
574	            l = DS4Q_MAX(0, DS4Q_MIN(3, l));
575	            L[16 * j + ii] = l;
576	        }
577	    }
578	
579	    for (int j = 0; j < QK_K; j += 128) {
580	        for (int l = 0; l < 32; l++) {
581	            qs_out[j / 4 + l] = L[j + l] | (L[j + l + 32] << 2) |
582	                                (L[j + l + 64] << 4) | (L[j + l + 96] << 6);
583	        }
584	    }
585	}
