587	static void ds4q_write_q2_k_block_weighted(const float *x, uint8_t *y, const float *quant_weights) {
588	    enum { scales_off = 0, qs_off = 16, d_off = 80, dmin_off = 82 };
589	    uint8_t L[QK_K];
590	    uint8_t Laux[16];
591	    float mins[QK_K / 16];
592	    float scales[QK_K / 16];
593	    float sw[QK_K / 16];
594	    float weight[16];
595	    uint8_t Ls[QK_K / 16], Lm[QK_K / 16];
596	    uint8_t *scales_out = y + scales_off;
597	    uint8_t *qs_out = y + qs_off;
598	
599	    memset(sw, 0, sizeof(sw));
600	    float sumx2 = 0;
601	    for (int j = 0; j < QK_K; j++) sumx2 += x[j] * x[j];
602	    float sigma2 = sumx2 / QK_K;
603	    for (int j = 0; j < QK_K / 16; j++) {
604	        const float *qw = quant_weights + 16 * j;
605	        for (int l = 0; l < 16; l++) weight[l] = qw[l] * sqrtf(sigma2 + x[16 * j + l] * x[16 * j + l]);
606	        for (int l = 0; l < QK_K / 16; l++) sw[j] += weight[l];
607	        scales[j] = ds4q_make_qkx3_quants(16, 3, x + 16 * j, weight, L + 16 * j,
608	                                           &mins[j], Laux, -0.9f, 0.05f, 36, false);
609	    }
610	
611	    float dm = ds4q_make_qp_quants(QK_K / 16, 15, scales, Ls, sw);
612	    float mm = ds4q_make_qp_quants(QK_K / 16, 15, mins, Lm, sw);
613	    uint16_t hd = ds4q_f32_to_f16(dm);
614	    uint16_t hmin = ds4q_f32_to_f16(mm);
615	    memcpy(y + d_off, &hd, sizeof(hd));
616	    memcpy(y + dmin_off, &hmin, sizeof(hmin));
617	    dm = ds4q_f16_to_f32(hd);
618	    mm = ds4q_f16_to_f32(hmin);
619	
620	    for (int j = 0; j < QK_K / 16; j++) scales_out[j] = Ls[j] | (Lm[j] << 4);
621	
622	    for (int j = 0; j < QK_K / 16; j++) {
623	        const float d = dm * (scales_out[j] & 0xF);
624	        if (!d) continue;
625	        const float m = mm * (scales_out[j] >> 4);
626	        for (int ii = 0; ii < 16; ii++) {
627	            int l = ds4q_nearest_int((x[16 * j + ii] + m) / d);
628	            l = DS4Q_MAX(0, DS4Q_MIN(3, l));
629	            L[16 * j + ii] = l;
630	        }
631	    }
632	
633	    for (int j = 0; j < QK_K; j += 128) {
634	        for (int l = 0; l < 32; l++) {
635	            qs_out[j / 4 + l] = L[j + l] | (L[j + l + 32] << 2) |
636	                                (L[j + l + 64] << 4) | (L[j + l + 96] << 6);
637	        }
638	    }
639	}
