663	typedef struct {
664	    uint64_t *grid;
665	    int *map;
666	    uint16_t *neighbours;
667	} ds4q_iq2_data;
668	
669	static ds4q_iq2_data ds4q_iq2_xxs_data;
670	
671	static int ds4q_iq2_compare_func(const void *left, const void *right) {
672	    const int *l = (const int *)left;
673	    const int *r = (const int *)right;
674	    return l[0] < r[0] ? -1 :
675	           l[0] > r[0] ?  1 :
676	           l[1] < r[1] ? -1 :
677	           l[1] > r[1] ?  1 : 0;
678	}
