680	/*
681	 * IQ2_XXS quantizes a 256-value row block as eight 32-value groups.  Each
682	 * group stores four 8-value grid indices plus four 7-bit sign masks; the
683	 * single f16 block scale is refined by 4-bit per-group scale nibbles.
684	 *
685	 * The grid is tiny, but not every possible 2-bit 8-tuple is allowed.  During
686	 * initialization we build the direct map for allowed tuples and a nearest-grid
687	 * list for the missing ones, matching the GGML search exactly.
688	 */
689	static void ds4q_iq2_xxs_init(void) {
690	    if (ds4q_iq2_xxs_data.grid) return;
691	    pthread_mutex_lock(&ds4q_init_mutex);
692	    if (ds4q_iq2_xxs_data.grid) {
693	        pthread_mutex_unlock(&ds4q_init_mutex);
694	        return;
695	    }
696	
697	    enum { grid_size = 256, map_size = 43692, neighbour_shells = 2 };
698	    static const uint16_t kgrid[256] = {
699	            0,     2,     5,     8,    10,    17,    20,    32,    34,    40,    42,    65,    68,    80,    88,    97,
700	          100,   128,   130,   138,   162,   257,   260,   272,   277,   320,   388,   408,   512,   514,   546,   642,
701	         1025,  1028,  1040,  1057,  1060,  1088,  1090,  1096,  1120,  1153,  1156,  1168,  1188,  1280,  1282,  1288,
702	         1312,  1350,  1385,  1408,  1425,  1545,  1552,  1600,  1668,  1700,  2048,  2053,  2056,  2068,  2088,  2113,
703	         2116,  2128,  2130,  2184,  2308,  2368,  2562,  2580,  4097,  4100,  4112,  4129,  4160,  4192,  4228,  4240,
704	         4245,  4352,  4360,  4384,  4432,  4442,  4480,  4644,  4677,  5120,  5128,  5152,  5157,  5193,  5248,  5400,
705	         5474,  5632,  5654,  6145,  6148,  6160,  6208,  6273,  6400,  6405,  6560,  6737,  8192,  8194,  8202,  8260,
706	         8289,  8320,  8322,  8489,  8520,  8704,  8706,  9217,  9220,  9232,  9280,  9302,  9472,  9537,  9572,  9872,
707	        10248, 10272, 10388, 10820, 16385, 16388, 16400, 16408, 16417, 16420, 16448, 16456, 16470, 16480, 16513, 16516,
708	        16528, 16640, 16672, 16737, 16768, 16773, 16897, 16912, 16968, 16982, 17000, 17408, 17416, 17440, 17536, 17561,
709	        17682, 17700, 17920, 18433, 18436, 18448, 18496, 18501, 18688, 18776, 18785, 18818, 19013, 19088, 20480, 20488,
710	        20497, 20505, 20512, 20608, 20616, 20740, 20802, 20900, 21137, 21648, 21650, 21770, 22017, 22100, 22528, 22545,
711	        22553, 22628, 22848, 23048, 24580, 24592, 24640, 24680, 24832, 24917, 25112, 25184, 25600, 25605, 25872, 25874,
712	        25988, 26690, 32768, 32770, 32778, 32833, 32898, 33028, 33048, 33088, 33297, 33793, 33796, 33808, 33813, 33856,
713	        33888, 34048, 34118, 34196, 34313, 34368, 34400, 34818, 35076, 35345, 36868, 36880, 36900, 36928, 37025, 37142,
714	        37248, 37445, 37888, 37922, 37956, 38225, 39041, 39200, 40962, 41040, 41093, 41225, 41472, 42008, 43088, 43268,
715	    };
716	
717	    uint64_t *grid = malloc((size_t)grid_size * sizeof(grid[0]));
718	    int *map = malloc((size_t)map_size * sizeof(map[0]));
719	    int *dist2 = malloc((size_t)2 * grid_size * sizeof(dist2[0]));
720	    assert(grid && map && dist2);
721	
722	    for (int k = 0; k < grid_size; k++) {
723	        int8_t *pos = (int8_t *)(grid + k);
724	        for (int i = 0; i < 8; i++) {
725	            int l = (kgrid[k] >> (2 * i)) & 3;
726	            pos[i] = 2 * l + 1;
727	        }
728	    }
729	
730	    for (int i = 0; i < map_size; i++) map[i] = -1;
731	    for (int i = 0; i < grid_size; i++) map[kgrid[i]] = i;
732	
733	    int8_t pos[8];
734	    int num_neighbors = 0;
735	    int num_not_in_map = 0;
736	    for (int i = 0; i < map_size; i++) {
737	        if (map[i] >= 0) continue;
738	        num_not_in_map++;
739	        for (int k = 0; k < 8; k++) pos[k] = 2 * ((i >> (2 * k)) & 3) + 1;
740	        for (int j = 0; j < grid_size; j++) {
741	            const int8_t *pg = (const int8_t *)(grid + j);
742	            int d2 = 0;
743	            for (int k = 0; k < 8; k++) d2 += (pg[k] - pos[k]) * (pg[k] - pos[k]);
744	            dist2[2 * j + 0] = d2;
745	            dist2[2 * j + 1] = j;
746	        }
747	        qsort(dist2, grid_size, 2 * sizeof(int), ds4q_iq2_compare_func);
748	        int d2 = dist2[0], have = 1;
749	        for (int j = 0; j < grid_size; j++) {
750	            if (dist2[2 * j] > d2) {
751	                if (have == neighbour_shells) break;
752	                d2 = dist2[2 * j];
753	                have++;
754	            }
755	            num_neighbors++;
756	        }
757	    }
758	
759	    uint16_t *neighbours = malloc((size_t)(num_neighbors + num_not_in_map) * sizeof(neighbours[0]));
760	    assert(neighbours);
761	    int counter = 0;
762	    for (int i = 0; i < map_size; i++) {
763	        if (map[i] >= 0) continue;
764	        for (int k = 0; k < 8; k++) pos[k] = 2 * ((i >> (2 * k)) & 3) + 1;
765	        for (int j = 0; j < grid_size; j++) {
766	            const int8_t *pg = (const int8_t *)(grid + j);
767	            int d2 = 0;
768	            for (int k = 0; k < 8; k++) d2 += (pg[k] - pos[k]) * (pg[k] - pos[k]);
769	            dist2[2 * j + 0] = d2;
770	            dist2[2 * j + 1] = j;
771	        }
772	        qsort(dist2, grid_size, 2 * sizeof(int), ds4q_iq2_compare_func);
773	        map[i] = -(counter + 1);
774	        int d2 = dist2[0], have = 1;
775	        uint16_t *start = &neighbours[counter++];
776	        int n = 0;
777	        for (int j = 0; j < grid_size; j++) {
778	            if (dist2[2 * j] > d2) {
779	                if (have == neighbour_shells) break;
780	                d2 = dist2[2 * j];
781	                have++;
782	            }
783	            neighbours[counter++] = (uint16_t)dist2[2 * j + 1];
784	            n++;
785	        }
786	        *start = (uint16_t)n;
787	    }
788	
789	    free(dist2);
790	    ds4q_iq2_xxs_data.map = map;
791	    ds4q_iq2_xxs_data.neighbours = neighbours;
792	    ds4q_iq2_xxs_data.grid = grid;
793	    pthread_mutex_unlock(&ds4q_init_mutex);
794	}
