796	static int ds4q_iq2_find_best_neighbour(const uint16_t *neighbours, const uint64_t *grid,
797	                                        const float *xval, const float *weight,
798	                                        float scale, uint8_t *L) {
799	    int num_neighbors = neighbours[0];
800	    assert(num_neighbors > 0);
801	    float best_d2 = FLT_MAX;
802	    int grid_index = -1;
803	    for (int j = 1; j <= num_neighbors; j++) {
804	        const int8_t *pg = (const int8_t *)(grid + neighbours[j]);
805	        float d2 = 0;
806	        for (int i = 0; i < 8; i++) {
807	            float q = pg[i];
808	            float diff = scale * q - xval[i];
809	            d2 += weight[i] * diff * diff;
810	        }
811	        if (d2 < best_d2) {
812	            best_d2 = d2;
813	            grid_index = neighbours[j];
814	        }
815	    }
816	    assert(grid_index >= 0);
817	    const int8_t *pg = (const int8_t *)(grid + grid_index);
818	    for (int i = 0; i < 8; i++) L[i] = (uint8_t)((pg[i] - 1) / 2);
819	    return grid_index;
820	}
821	
822	static void ds4q_write_iq2_xxs_block(const float *x, uint8_t *y, const float *quant_weights) {
823	    enum { d_off = 0, qs_off = 2, block_size = 32, k_max_q = 3 };
824	    assert(quant_weights);
825	
826	    uint32_t q2[2 * (QK_K / block_size)];
827	    float scales[QK_K / block_size];
828	    float weight[block_size];
829	    float xval[block_size];
830	    uint8_t L[block_size];
831	    uint8_t Laux[block_size];
832	    float waux[block_size];
833	    uint8_t block_signs[4];
834	
835	    uint16_t hd = ds4q_f32_to_f16(0.0f);
836	    memcpy(y + d_off, &hd, sizeof(hd));
837	    memset(q2, 0, sizeof(q2));
838	
839	    const uint64_t *grid = ds4q_iq2_xxs_data.grid;
840	    const int *map = ds4q_iq2_xxs_data.map;
841	    const uint16_t *neighbours = ds4q_iq2_xxs_data.neighbours;
842	    assert(grid && map && neighbours);
843	
844	    float sumx2 = 0;
845	    for (int i = 0; i < QK_K; i++) sumx2 += x[i] * x[i];
846	    float sigma2 = sumx2 / QK_K;
847	    float max_scale = 0;
848	
849	    for (int ib = 0; ib < QK_K / block_size; ib++) {
850	        const float *xb = x + block_size * ib;
851	        const float *qw = quant_weights + block_size * ib;
852	        for (int i = 0; i < block_size; i++) {
853	            weight[i] = qw[i] * sqrtf(sigma2 + xb[i] * xb[i]);
854	            waux[i] = sqrtf(weight[i]);
855	        }
856	        for (int k = 0; k < 4; k++) {
857	            int nflip = 0;
858	            uint8_t s = 0;
859	            for (int i = 0; i < 8; i++) {
860	                float v = xb[8 * k + i];
861	                if (v >= 0) {
862	                    xval[8 * k + i] = v;
863	                } else {
864	                    xval[8 * k + i] = -v;
865	                    nflip++;
866	                    s |= (uint8_t)(1u << i);
867	                }
868	            }
869	            if (nflip % 2) {
870	                int imin = 0;
871	                float min = weight[8 * k] * xb[8 * k] * xb[8 * k];
872	                for (int i = 1; i < 8; i++) {
873	                    float ax = weight[8 * k + i] * xb[8 * k + i] * xb[8 * k + i];
874	                    if (ax < min) {
875	                        min = ax;
876	                        imin = i;
877	                    }
878	                }
879	                xval[8 * k + imin] = -xval[8 * k + imin];
880	                s ^= (uint8_t)(1u << imin);
881	            }
882	            block_signs[k] = s & 127;
883	        }
884	
885	        float max = xval[0];
886	        for (int i = 1; i < block_size; i++) max = DS4Q_MAX(max, xval[i]);
887	        if (max < DS4Q_GROUP_MAX_EPS) {
888	            scales[ib] = 0;
889	            memset(L, 0, sizeof(L));
890	            continue;
891	        }
892	
893	        float scale = ds4q_make_qp_quants(block_size, k_max_q + 1, xval, L, weight);
894	        float eff_max = scale * k_max_q;
895	        if (eff_max <= 0) {
896	            scales[ib] = 0;
897	            memset(L, 0, sizeof(L));
898	            continue;
899	        }
900	
901	        float best = 0;
902	        for (int is = -6; is <= 6; is++) {
903	            float id = (2 * k_max_q - 1 + is * 0.1f) / eff_max;
904	            float this_scale = 1 / id;
905	            for (int k = 0; k < 4; k++) {
906	                uint16_t u = 0;
907	                for (int i = 0; i < 8; i++) {
908	                    int l = ds4q_nearest_int(0.5f * (id * xval[8 * k + i] - 1));
909	                    l = DS4Q_MAX(0, DS4Q_MIN(k_max_q - 1, l));
910	                    Laux[8 * k + i] = (uint8_t)l;
911	                    u |= (uint16_t)(l << (2 * i));
912	                }
913	                int grid_index = map[u];
914	                if (grid_index < 0) {
915	                    const uint16_t *nbs = neighbours - map[u] - 1;
916	                    ds4q_iq2_find_best_neighbour(nbs, grid, xval + 8 * k, waux + 8 * k,
917	                                                 this_scale, Laux + 8 * k);
918	                }
919	            }
920	            float sumqx = 0, sumq2 = 0;
921	            for (int i = 0; i < block_size; i++) {
922	                float w = weight[i];
923	                float q = 2 * Laux[i] + 1;
924	                sumqx += w * xval[i] * q;
925	                sumq2 += w * q * q;
926	            }
927	            if (sumq2 > 0 && sumqx * sumqx > best * sumq2) {
928	                scale = sumqx / sumq2;
929	                best = scale * sumqx;
930	                memcpy(L, Laux, sizeof(L));
931	            }
932	        }
933	
934	        if (scale > 0) {
935	            float id = 1 / scale;
936	            for (int k = 0; k < 4; k++) {
937	                uint16_t u = 0;
938	                for (int i = 0; i < 8; i++) {
939	                    int l = ds4q_nearest_int(0.5f * (id * xval[8 * k + i] - 1));
940	                    l = DS4Q_MAX(0, DS4Q_MIN(k_max_q - 1, l));
941	                    u |= (uint16_t)(l << (2 * i));
942	                }
943	                int grid_index = map[u];
944	                if (grid_index < 0) {
945	                    const uint16_t *nbs = neighbours - map[u] - 1;
946	                    grid_index = ds4q_iq2_find_best_neighbour(nbs, grid, xval + 8 * k,
947	                                                              waux + 8 * k, scale, L + 8 * k);
948	                }
949	                const int8_t *pg = (const int8_t *)(grid + grid_index);
950	                for (int i = 0; i < 8; i++) L[8 * k + i] = (uint8_t)((pg[i] - 1) / 2);
951	            }
952	            float sumqx = 0, sumq2 = 0;
953	            for (int i = 0; i < block_size; i++) {
954	                float w = weight[i];
955	                float q = 2 * L[i] + 1;
956	                sumqx += w * xval[i] * q;
957	                sumq2 += w * q * q;
958	            }
959	            if (sumq2 > 0) scale = sumqx / sumq2;
960	        }
961	
962	        if (scale < 0) {
963	            scale = -scale;
964	            for (int k = 0; k < 4; k++) block_signs[k] = (~block_signs[k]) & 127;
965	        }
966	
967	        for (int k = 0; k < 4; k++) {
968	            uint16_t u = 0;
969	            for (int i = 0; i < 8; i++) u |= (uint16_t)(L[8 * k + i] << (2 * i));
970	            int grid_index = map[u];
971	            assert(grid_index >= 0);
972	            q2[2 * ib + 0] |= (uint32_t)grid_index << (8 * k);
973	            q2[2 * ib + 1] |= (uint32_t)block_signs[k] << (7 * k);
974	        }
975	        assert(scale >= 0);
976	        scales[ib] = scale;
977	        max_scale = DS4Q_MAX(max_scale, scale);
978	    }
979	
980	    if (!max_scale) {
981	        memset(y + qs_off, 0, QK_K / 4);
982	        return;
983	    }
984	
985	    float d = max_scale / 31;
986	    hd = ds4q_f32_to_f16(d);
987	    memcpy(y + d_off, &hd, sizeof(hd));
988	    float id = 1 / d;
989	    for (int ib = 0; ib < QK_K / block_size; ib++) {
990	        int l = ds4q_nearest_int(0.5f * (id * scales[ib] - 1));
991	        l = DS4Q_MAX(0, DS4Q_MIN(15, l));
992	        q2[2 * ib + 1] |= (uint32_t)l << 28;
993	    }
994	    memcpy(y + qs_off, q2, QK_K / 4);
995	}
996	
997	static size_t ds4q_quantize_iq2_xxs(const float *src, void *dst, int64_t start,
998	                                    int64_t nrows, int64_t ncols, const float *quant_weights) {
999	    assert(quant_weights);
1000	    ds4q_iq2_xxs_init();
1001	    const size_t row_size = ds4q_row_size(DS4Q_TYPE_IQ2_XXS, ncols);
1002	    const int64_t start_row = start / ncols;
1003	    uint8_t *out = (uint8_t *)dst + (size_t)start_row * row_size;
1004	    const int64_t blocks_per_row = ncols / QK_K;
1005	
1006	    for (int64_t row = 0; row < nrows; row++) {
1007	        const float *xrow = src + start + (size_t)row * (size_t)ncols;
1008	        for (int64_t b = 0; b < blocks_per_row; b++) {
1009	            uint8_t *block = out + (size_t)row * row_size + (size_t)b * ds4q_type_traits[DS4Q_TYPE_IQ2_XXS].type_size;
1010	            ds4q_write_iq2_xxs_block(xrow + (size_t)b * QK_K, block,
1011	                                     quant_weights + (size_t)b * QK_K);
1012	        }
1013	    }
1014	    return (size_t)nrows * row_size;
1015	}
1016	
1017	const char *ds4q_type_name(ds4q_type type) {
1018	    if (type < 0 || type >= DS4Q_TYPE_COUNT) return NULL;
1019	    return ds4q_type_traits[type].name;
1020	}
1021	
1022	bool ds4q_can_quantize(ds4q_type type) {
1023	    if (type < 0 || type >= DS4Q_TYPE_COUNT) return false;
1024	    return ds4q_type_traits[type].can_quantize;
1025	}
1026	
1027	int64_t ds4q_block_size(ds4q_type type) {
1028	    if (type < 0 || type >= DS4Q_TYPE_COUNT) return 0;
1029	    return ds4q_type_traits[type].block_size;
1030	}
1031	
1032	size_t ds4q_row_size(ds4q_type type, int64_t ne) {
1033	    if (type < 0 || type >= DS4Q_TYPE_COUNT) return 0;
1034	    const ds4q_traits *tr = &ds4q_type_traits[type];
1035	    if (tr->block_size <= 0 || tr->type_size == 0 || ne % tr->block_size != 0) return 0;
1036	    return tr->type_size * (size_t)(ne / tr->block_size);
1037	}
1038	
1039	bool ds4q_requires_imatrix(ds4q_type type) {
1040	    if (type < 0 || type >= DS4Q_TYPE_COUNT) return false;
1041	    return ds4q_type_traits[type].requires_imatrix;
1042	}
1043	
1044	void ds4q_quantize_init(ds4q_type type) {
1045	    if (type == DS4Q_TYPE_IQ2_XXS) {
1046	        ds4q_iq2_xxs_init();
1047	    }
1048	}
1049	
1050	size_t ds4q_quantize_chunk(ds4q_type type, const float *src, void *dst,
1051	                           int64_t start, int64_t nrows, int64_t ncols,
1052	                           const float *imatrix) {
1053	    if (type == DS4Q_TYPE_Q8_0) {
1054	        (void)imatrix;
1055	        return ds4q_quantize_q8_0(src, dst, start, nrows, ncols);
1056	    }
1057	    if (type == DS4Q_TYPE_Q2_K) {
1058	        return ds4q_quantize_q2_k(src, dst, start, nrows, ncols, imatrix);
1059	    }
1060	    if (type == DS4Q_TYPE_Q4_K) {
1061	        return ds4q_quantize_q4_k(src, dst, start, nrows, ncols, imatrix);
1062	    }
1063	    if (type == DS4Q_TYPE_IQ2_XXS) {
1064	        return ds4q_quantize_iq2_xxs(src, dst, start, nrows, ncols, imatrix);
1065	    }
1066	    (void)src;
1067	    (void)dst;
1068	    (void)start;
1069	    (void)nrows;
1070	    (void)ncols;
1071	    (void)imatrix;
1072	    assert(!"unsupported DS4 quantization target");
1073	    return 0;
1074	}
1075	
1076	float ds4q_f16_to_f32(uint16_t bits) {
1077	    const uint32_t w = (uint32_t)bits << 16;
1078	    const uint32_t sign = w & UINT32_C(0x80000000);
1079	    const uint32_t two_w = w + w;
1080	    const uint32_t exp_offset = UINT32_C(0xE0) << 23;
1081	    const float exp_scale = 0x1.0p-112f;
1082	    const float normalized_value = ds4q_f32_from_bits((two_w >> 4) + exp_offset) * exp_scale;
1083	    const uint32_t magic_mask = UINT32_C(126) << 23;
1084	    const float magic_bias = 0.5f;
1085	    const float denormalized_value = ds4q_f32_from_bits((two_w >> 17) | magic_mask) - magic_bias;
1086	    const uint32_t denormalized_cutoff = UINT32_C(1) << 27;
1087	    const uint32_t result = sign |
1088	        (two_w < denormalized_cutoff ? ds4q_f32_to_bits(denormalized_value) : ds4q_f32_to_bits(normalized_value));
1089	    return ds4q_f32_from_bits(result);
1090	}
1091	
1092	float ds4q_bf16_to_f32(uint16_t bits) {
1093	    return ds4q_f32_from_bits((uint32_t)bits << 16);
1094	}
1095	
1096	void ds4q_f32_to_f16_row(const float *src, uint16_t *dst, int64_t n) {
1097	    for (int64_t i = 0; i < n; i++) dst[i] = ds4q_f32_to_f16(src[i]);
1098	}
1099	
1100	void ds4q_f32_to_bf16_row(const float *src, uint16_t *dst, int64_t n) {
1101	    for (int64_t i = 0; i < n; i++) {
1102	        uint32_t bits = ds4q_f32_to_bits(src[i]);
1103	        if ((bits & UINT32_C(0x7fffffff)) > UINT32_C(0x7f800000)) {
1104	            dst[i] = (uint16_t)((bits >> 16) | 64);
1105	        } else {
1106	            dst[i] = (uint16_t)((bits + (UINT32_C(0x7fff) + ((bits >> 16) & 1))) >> 16);
1107	        }
1108	    }
1109	}
