2584	static void ds4_quantize_row_q8_K(const float *x, block_q8_K *y, int64_t k) {
2585	    if (k % QK_K != 0) ds4_die("Q8_K quantization length is not QK_K aligned");
2586	    const int64_t nb = k / QK_K;
2587	
2588	    for (int64_t b = 0; b < nb; b++) {
2589	        float max = 0.0f;
2590	        float amax = 0.0f;
2591	        for (int j = 0; j < QK_K; j++) {
2592	            const float ax = fabsf(x[j]);
2593	            if (ax > amax) {
2594	                amax = ax;
2595	                max = x[j];
2596	            }
2597	        }
2598	
2599	        if (amax == 0.0f) {
2600	            y[b].d = 0.0f;
2601	            memset(y[b].qs, 0, sizeof(y[b].qs));
2602	            memset(y[b].bsums, 0, sizeof(y[b].bsums));
2603	            x += QK_K;
2604	            continue;
2605	        }
2606	
2607	        const float iscale = -127.0f / max;
2608	        for (int j = 0; j < QK_K; j++) {
2609	            int v = (int)lrintf(iscale * x[j]);
2610	            if (v > 127) v = 127;
2611	            if (v < -128) v = -128;
2612	            y[b].qs[j] = (int8_t)v;
2613	        }
2614	        for (int j = 0; j < QK_K / 16; j++) {
2615	            int sum = 0;
2616	            for (int i = 0; i < 16; i++) sum += y[b].qs[j * 16 + i];
2617	            y[b].bsums[j] = (int16_t)sum;
2618	        }
2619	        y[b].d = 1.0f / iscale;
2620	        x += QK_K;
2621	    }
